def run_packing():
    n = 26
    best_sum = 0.0
    best_centers = np.zeros((n, 2))
    best_radii = np.zeros(n)

    # Initial configurations
    initial_configs = [
        generate_hexagonal_config(n),
        generate_corner_config(n),
        generate_corner_hexagonal_config(n),
    ]

    # Optimization function with enhanced boundary and corner handling
    def optimize_config(centers):
        # Initialize radii based on minimum distances to neighbors and boundaries
        radii = np.zeros(n)
        for i in range(n):
            min_dist = np.inf
            for j in range(n):
                if i != j:
                    dx = centers[i][0] - centers[j][0]
                    dy = centers[i][1] - centers[j][1]
                    dist = np.sqrt(dx ** 2 + dy ** 2)
                    if dist < min_dist:
                        min_dist = dist
            r = min_dist / 2
            r = min(r, centers[i][0])
            r = min(r, 1 - centers[i][0])
            r = min(r, centers[i][1])
            r = min(r, 1 - centers[i][1])
            radii[i] = r

        # Objective function to minimize (negative of sum of radii)
        def objective(x):
            return -np.sum(x)

        # Constraints: no overlap and within unit square
        def constraints(x):
            for i in range(n):
                x_i, y_i = centers[i]
                r_i = x[i]
                if (x_i - r_i < -1e-12 or x_i + r_i > 1 + 1e-12 or
                    y_i - r_i < -1e-12 or y_i + r_i > 1 + 1e-12):
                    return -np.inf
            for i in range(n):
                for j in range(i + 1, n):
                    dx = centers[i][0] - centers[j][0]
                    dy = centers[i][1] - centers[j][1]
                    dist = np.sqrt(dx ** 2 + dy ** 2)
                    if dist < x[i] + x[j] - 1e-12:
                        return -np.inf
            return 0.0

        # Bounds for radii: non-negative
        bounds = [(0, 1) for _ in range(n)]

        # Run the optimization with SLSQP method (better for constrained optimization)
        result = optimize.minimize(
            objective,
            radii,
            bounds=bounds,
            constraints={"type": "ineq", "fun": constraints},
            method="SLSQP",
            options={"ftol": 1e-9, "maxiter": 500, "disp": False}
        )

        final_radii = result.x
        final_centers = centers.copy()

        # Validate packing
        valid, message = validate_packing(final_centers, final_radii)
        if not valid:
            print(f"Validation Failed: {message}")
            return None, None, 0.0

        return final_centers, final_radii, np.sum(final_radii)

    # Run optimization on initial configurations
    for centers in initial_configs:
        centers, radii, sum_radii = optimize_config(centers)
        if centers is not None and sum_radii > best_sum:
            best_sum = sum_radii
            best_centers = centers.copy()
            best_radii = radii.copy()

    # Advanced refinement with multiple trials and perturbations
    for _ in range(100):  # Run more refinement steps
        for i in range(n):
            # Perturb the center of the i-th circle
            perturb = np.random.rand(2) * 0.1 - 0.05
            perturbed_centers = best_centers.copy()
            perturbed_centers[i] += perturb

            # Re-initialize radii based on new configuration
            radii = np.zeros(n)
            for j in range(n):
                min_dist = np.inf
                for k in range(n):
                    if j != k:
                        dx = perturbed_centers[j][0] - perturbed_centers[k][0]
                        dy = perturbed_centers[j][1] - perturbed_centers[k][1]
                        dist = np.sqrt(dx ** 2 + dy ** 2)
                        if dist < min_dist:
                            min_dist = dist
                r = min_dist / 2
                r = min(r, perturbed_centers[j][0])
                r = min(r, 1 - perturbed_centers[j][0])
                r = min(r, perturbed_centers[j][1])
                r = min(r, 1 - perturbed_centers[j][1])
                radii[j] = r

            # Run the optimization
            centers, radii, sum_radii = optimize_config(perturbed_centers)
            if centers is not None and sum_radii > best_sum:
                best_sum = sum_radii
                best_centers = centers.copy()
                best_radii = radii.copy()

    # Manual perturbation to encourage boundary utilization
    corners = np.array([
        [1e-5, 1e-5],
        [1 - 1e-5, 1e-5],
        [1e-5, 1 - 1e-5],
        [1 - 1e-5, 1 - 1e-5]
    ])
    for i in range(n):
        for corner in corners:
            perturbed_centers = best_centers.copy()
            perturbed_centers[i] = corner

            # Re-initialize radii based on new configuration
            radii = np.zeros(n)
            for j in range(n):
                min_dist = np.inf
                for k in range(n):
                    if j != k:
                        dx = perturbed_centers[j][0] - perturbed_centers[k][0]
                        dy = perturbed_centers[j][1] - perturbed_centers[k][1]
                        dist = np.sqrt(dx ** 2 + dy ** 2)
                        if dist < min_dist:
                            min_dist = dist
                r = min_dist / 2
                r = min(r, perturbed_centers[j][0])
                r = min(r, 1 - perturbed_centers[j][0])
                r = min(r, perturbed_centers[j][1])
                r = min(r, 1 - perturbed_centers[j][1])
                radii[j] = r

            # Run the optimization
            centers, radii, sum_radii = optimize_config(perturbed_centers)
            if centers is not None and sum_radii > best_sum:
                best_sum = sum_radii
                best_centers = centers.copy()
                best_radii = radii.copy()

    return best_centers, best_radii, best_sum
